PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?country ?countryLabel ?dish ?dishLabel WHERE {
  VALUES ?country {
    wd:Q40 wd:Q213 wd:Q214 wd:Q36 wd:Q218 wd:Q39 wd:Q697 wd:Q38
  }
  .
  ?dish wdt:P495 ?country .
  ?dish wdt:P31 / wdt:P279 * wd:Q2095 .
  OPTIONAL {
    ?country rdfs:label ?countryLabel
    FILTER(LANG(?countryLabel) = 'en')
  }
  OPTIONAL {
    ?dish rdfs:label ?dishLabel
    FILTER(LANG(?dishLabel) = 'en')
  }
}
ORDER BY ?country
